mapper.select:
SELECT b.id, b.payee, b.amount, b.transaction_time, b.payment_method_id, pm.name AS payment_method_name, b.transaction_no, b.category_id, bc.name AS category_name, b.remark, b.create_time FROM bill b LEFT JOIN payment_method pm ON b.payment_method_id = pm.id LEFT JOIN bill_category bc ON b.category_id = bc.id
AND b.transaction_time >= #{startTime}
AND b.transaction_time <= #{endTime}
AND b.payment_method_id = #{paymentMethodId}
AND b.category_id = #{categoryId}
AND b.amount < 0
AND b.amount > 0
ORDER BY b.transaction_time DESC, b.create_time DESC

SELECT COALESCE(SUM(amount), 0)
FROM bill

    amount > 0

        AND transaction_time >= #{startTime}


        AND transaction_time <= #{endTime}

SELECT COALESCE(ABS(SUM(amount)), 0)
FROM bill

    amount < 0

        AND transaction_time >= #{startTime}


        AND transaction_time <= #{endTime}

SELECT bc.id AS categoryId, bc.name AS categoryName, COALESCE(SUM(ABS(b.amount)), 0) AS amount, bc.type AS type FROM bill b LEFT JOIN bill_category bc ON b.category_id = bc.id
AND b.transaction_time >= #{startTime}
AND b.transaction_time <= #{endTime}
GROUP BY bc.id, bc.name, bc.type ORDER BY amount DESC

SELECT pm.id AS paymentMethodId, pm.name AS paymentMethodName, COALESCE(SUM(ABS(b.amount)), 0) AS amount FROM bill b LEFT JOIN payment_method pm ON b.payment_method_id = pm.id
AND b.transaction_time >= #{startTime}
AND b.transaction_time <= #{endTime}
GROUP BY pm.id, pm.name ORDER BY amount DESC
